import{k as e,p as t,u as n}from"./chunks/runtime-core.esm-bundler.PK8HO-US.js";import{t as r}from"./chunks/plugin-vue_export-helper.DrfHhw6c.js";import{i,n as a,r as o,t as s}from"./chunks/windows-wizard-screenshot.QBlzzreT.js";const c=JSON.parse(`{"title":"Встановлення Java у Windows","description":"Покрокова інструкція щодо встановлення Java на Windows.","frontmatter":{"title":"Встановлення Java у Windows","description":"Покрокова інструкція щодо встановлення Java на Windows.","authors":["IMB11"],"files":[]},"headers":[],"relativePath":"uk_ua/1.21.10/players/installing-java/windows.md","filePath":"versions/1.21.10/translated/uk_ua/players/installing-java/windows.md","lastUpdated":1766682904000}`);var l={name:`uk_ua/1.21.10/players/installing-java/windows.md`};function u(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="h1" tabindex="-1">Встановлення Java у Windows <a class="header-anchor" href="#h1" aria-label="Permalink to “Встановлення Java у Windows”">​</a></h1><p>Інструкція по тому як встановити Java 21 у Windows.</p><p>Запускач Minecraft постачається з власною інсталяцією Java, тому цей розділ актуальний, лише якщо ви хочете використовувати встановлювач на основі Fabric <code>.jar</code> або якщо ви хочете використовувати сервер Minecraft <code>.jar</code>.</p><h2 id="1-check-if-java-is-already-installed" tabindex="-1">1. Перевірте, чи Java уже встановлено <a class="header-anchor" href="#1-check-if-java-is-already-installed" aria-label="Permalink to “1. Перевірте, чи Java уже встановлено”">​</a></h2><p>Щоб перевірити, чи Java вже встановлено, потрібно спочатку відкрити командний рядок.</p><p>Ви можете зробити це, натиснувши <kbd>Win</kbd> <kbd>R</kbd> і ввівши <code>cmd.exe</code> у поле, що з’явиться.</p><p><img src="/assets/players/installing-java/windows-run-dialog.png" alt="Діалогове вікно запуску Windows із &quot;cmd.exe&quot; на панелі запуску" loading="lazy"></p><p>Відкривши командний рядок, введіть <code>java -version</code> і натисніть <kbd>Enter</kbd>.</p><p>Якщо команда виконана успішно, ви побачите щось подібне. Якщо команда не вдалася, перейдіть до наступного кроку.</p><p><img src="/assets/players/installing-java/windows-java-version.png" alt="Командний рядок із введеним &quot;java -version&quot;" loading="lazy"></p><div class="warning custom-block"><p class="custom-block-title custom-block-title-default">WARNING</p><p>Щоб використовувати Minecraft 1.21, вам знадобиться встановити принаймні Java 21. Якщо ця команда показує будь-яку версію, нижчу за 21, вам потрібно буде оновити встановлювач Java.</p></div><h2 id="2-download-the-java-installer" tabindex="-1">2. Завантажити завантажувач Java 21 <a class="header-anchor" href="#2-download-the-java-installer" aria-label="Permalink to “2. Завантажити завантажувач Java 21”">​</a></h2><p>Щоб установити Java 21, вам потрібно буде завантажити програму встановлення з Adoptium.</p><p>Ви захочете завантажити версію <code>Windows Installer (.msi)</code>:</p><p><img src="/assets/players/installing-java/windows-download-java.png" alt="Сторінка завантаження Adoptium із виділеним встановлювачем Windows (.msi)" loading="lazy"></p><p>Вам слід вибрати «x86», якщо у вас 32-розрядна операційна система, або «x64», якщо у вас 64-розрядна операційна система.</p><p>Більшість сучасних комп’ютерів матиме 64-розрядну операційну систему. Якщо ви не впевнені, спробуйте скористатися 64-розрядним завантаженням.</p><h2 id="3-run-the-installer" tabindex="-1">3. Запустіть встановлювач! <a class="header-anchor" href="#3-run-the-installer" aria-label="Permalink to “3. Запустіть встановлювач!”">​</a></h2><p>Виконайте кроки встановлювача, щоб встановити Java 21. Коли ви перейдете на цю сторінку, ви повинні встановити такі функції на «Уся функція буде встановлена ​​на локальному жорсткому диску»:</p><ul><li><code>Установити змінну середовища JAVA_HOME</code> - її буде додано до вашого ШЛЯХУ.</li><li><code>JavaSoft (Oracle) registry keys</code></li></ul><p><img src="/assets/players/installing-java/windows-wizard-screenshot.png" alt="Встановлювач Java 21 із виділеними параметрами «Встановити змінну JAVA_HOME» і «ключами реєстру JavaSoft (Oracle)»" loading="lazy"></p><p>Зробивши це, ви можете натиснути <code>Next</code> і продовжити встановлення.</p><h2 id="4-verify-that-java-is-installed" tabindex="-1">4. Перевірте, чи встановлено Java 21 <a class="header-anchor" href="#4-verify-that-java-is-installed" aria-label="Permalink to “4. Перевірте, чи встановлено Java 21”">​</a></h2><p>Після завершення встановлення ви можете переконатися, що Java 21 встановлено, знову відкривши командний рядок і ввівши <code>java -version</code>.</p><p>Якщо команда виконана успішно, ви побачите щось подібне до показаного раніше, де показана версія Java:</p><p><img src="/assets/players/installing-java/windows-java-version.png" alt="Командний рядок із введеним &quot;java -version&quot;" loading="lazy"></p><p>Якщо у вас виникнуть проблеми, не соромтеся звертатися по допомогу до <a href="https://discord.gg/v6v4pMv" target="_blank" rel="noreferrer">Fabric Discord</a> на каналі #player-support.</p>`,27)]])}var d=r(l,[[`render`,u]]);export{c as __pageData,d as default};